32	  const validatePassword = (pwd: string): string[] => {
33	    const errors: string[] = [];
34	    if (pwd.length < 8) errors.push("At least 8 characters");
35	    if (!/[A-Z]/.test(pwd)) errors.push("One uppercase letter");
36	    if (!/[a-z]/.test(pwd)) errors.push("One lowercase letter");
37	    if (!/[0-9]/.test(pwd)) errors.push("One number");
38	    if (!/[^A-Za-z0-9]/.test(pwd)) errors.push("One special character");
39	    return errors;
40	  };
41	
42	  const handlePasswordChange = (value: string) => {
43	    setPassword(value);
44	    if (isSignup) setPasswordErrors(validatePassword(value));
45	  };
46	
47	  useEffect(() => {
48	    // Check if user is already logged in
49	    supabase.auth.getSession().then(async ({ data: { session } }) => {
50	      if (session) {
51	        const { data: aalData } = await supabase.auth.mfa.getAuthenticatorAssuranceLevel();
52	        if (aalData?.nextLevel === "aal2" && aalData?.nextLevel !== aalData?.currentLevel) {
53	          navigate("/mfa-verify", { replace: true });
54	        } else {
55	          navigate("/kira", { replace: true });
56	        }
57	      }
58	    });
59	
60	    // Listen for auth state changes (for OAuth redirects)
61	    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
62	      if (event === 'SIGNED_IN' && session) {
63	        const { data: aalData } = await supabase.auth.mfa.getAuthenticatorAssuranceLevel();
64	        if (aalData?.nextLevel === "aal2" && aalData?.nextLevel !== aalData?.currentLevel) {
65	          navigate("/mfa-verify", { replace: true });
66	        } else {
67	          navigate("/kira", { replace: true });
68	        }
69	      }
70	    });
71	
72	    return () => subscription.unsubscribe();
73	  }, [navigate]);
