2	import { Link, useNavigate, useSearchParams } from "react-router-dom";
3	import { Button } from "@/components/ui/button";
4	import { Card } from "@/components/ui/card";
5	import { Input } from "@/components/ui/input";
6	import { Label } from "@/components/ui/label";
7	import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
8	import { supabase } from "@/integrations/supabase/client";
9	import { useToast } from "@/hooks/use-toast";
10	import { Eye, EyeOff, Loader2, User, Building2 } from "lucide-react";
11	import { Checkbox } from "@/components/ui/checkbox";
12	import { cn } from "@/lib/utils";
13	
14	const hasOAuthCallback = () => {
15	  const params = new URLSearchParams(window.location.search);
16	  return params.has("code") || window.location.hash.includes("access_token=");
17	};
18	
19	const Auth = () => {
20	  const navigate = useNavigate();
21	  const [searchParams] = useSearchParams();
22	  const { toast } = useToast();
23	  const [isSignup, setIsSignup] = useState(searchParams.get("mode") === "signup");
24	  const [email, setEmail] = useState("");
25	  const [password, setPassword] = useState("");
26	  const [showPassword, setShowPassword] = useState(false);
27	  const [showForgotPassword, setShowForgotPassword] = useState(false);
28	  const [resetEmail, setResetEmail] = useState("");
29	  const [isResetting, setIsResetting] = useState(false);
30	  const [isGoogleLoading, setIsGoogleLoading] = useState(false);
31	  // const [isAppleLoading, setIsAppleLoading] = useState(false);
32	  const [isLoading, setIsLoading] = useState(false);
33	  const [userType, setUserType] = useState<"creator" | "brand">("creator");
34	  const [termsAccepted, setTermsAccepted] = useState(false);
35	  const [passwordErrors, setPasswordErrors] = useState<string[]>([]);
36	  // True when we landed here from a Google OAuth redirect — hide the form while Supabase exchanges the code.
37	  const [isProcessingOAuth, setIsProcessingOAuth] = useState(hasOAuthCallback);
38	
39	  const validatePassword = (pwd: string): string[] => {
40	    const errors: string[] = [];
41	    if (pwd.length < 8) errors.push("At least 8 characters");
42	    if (!/[A-Z]/.test(pwd)) errors.push("One uppercase letter");
43	    if (!/[a-z]/.test(pwd)) errors.push("One lowercase letter");
44	    if (!/[0-9]/.test(pwd)) errors.push("One number");
45	    if (!/[^A-Za-z0-9]/.test(pwd)) errors.push("One special character");
46	    return errors;
47	  };
48	
49	  const handlePasswordChange = (value: string) => {
50	    setPassword(value);
51	    if (isSignup) setPasswordErrors(validatePassword(value));
52	  };
53	
54	  useEffect(() => {
