      "pg_get_functiondef": "CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  base_handle TEXT;
  final_handle TEXT;
  counter INTEGER := 0;
BEGIN
  base_handle := LOWER(
    REGEXP_REPLACE(
      COALESCE(NEW.raw_user_metadata->>'handle', SPLIT_PART(NEW.email, '@', 1)),
      '[^a-z0-9_]', '_', 'g'
    )
  );

  final_handle := base_handle;

  WHILE EXISTS (SELECT 1 FROM public.profiles WHERE handle = final_handle) LOOP
    counter := counter + 1;
    final_handle := base_handle || '_' || counter;
  END LOOP;

  INSERT INTO public.profiles (id, user_type, handle, email)
  VALUES (
    NEW.id,
    COALESCE(NEW.raw_user_metadata->>'user_type', 'creator')::public.user_type,
    final_handle,
    NEW.email
  );

  RETURN NEW;
END;
$function$
"
