CREATE OR REPLACE FUNCTION public.test_column_access()
RETURNS trigger LANGUAGE plpgsql AS \$\$
DECLARE
  val TEXT;
BEGIN
  -- Test accessing with WRONG name (raw_user_metadata)
  val := NEW.raw_user_metadata::text;
  RAISE NOTICE 'raw_user_metadata = %', val;
  -- Test accessing with CORRECT name (raw_user_meta_data)
  val := NEW.raw_user_meta_data::text;
  RAISE NOTICE 'raw_user_meta_data = %', val;
  RETURN NEW;
END;
\$\$;
DROP TRIGGER IF EXISTS test_col_access ON auth.users;
CREATE TRIGGER test_col_access BEFORE INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.test_column_access();
" 2>&1

