-- Fix handle_new_user trigger: correct column name is raw_user_meta_data (with underscore),
-- not raw_user_metadata. The previous migration introduced this typo, breaking all new
-- email/password signups since April 29 2026.

CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER SET search_path = public
AS $$
DECLARE
  base_handle TEXT;
  final_handle TEXT;
  counter INTEGER := 0;
BEGIN
  base_handle := LOWER(
    REGEXP_REPLACE(
      COALESCE(NEW.raw_user_meta_data->>'handle', SPLIT_PART(NEW.email, '@', 1)),
      '[^a-z0-9_]', '_', 'g'
    )
  );

  final_handle := base_handle;

  WHILE EXISTS (SELECT 1 FROM public.profiles WHERE handle = final_handle) LOOP
    counter := counter + 1;
    final_handle := base_handle || '_' || counter;
  END LOOP;

  INSERT INTO public.profiles (id, user_type, handle, email)
  VALUES (
    NEW.id,
    COALESCE(NEW.raw_user_meta_data->>'user_type', 'creator')::public.user_type,
    final_handle,
    NEW.email
  );

  RETURN NEW;
END;
$$;

